import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.tunombre.gamevault.catalogo.api.eventos.VideojuegoEvent;
import com.tunombre.gamevault.config.RabbitMQConfig;
import lombok.RequiredArgsConstructor;
import org.springframework.amqp.rabbit.core.RabbitTemplate;
import org.springframework.stereotype.Component;

@Component
@RequiredArgsConstructor
public class VideojuegoEventPublisher {
    private final RabbitTemplate rabbitTemplate;
    private final ObjectMapper objectMapper;

    public void publicar(String tipo, Long videojuegoId) {
        String accion = switch (tipo) {
            case VideojuegoEvent.VIDEOJUEGO_CREADO -&gt; "creado";
            case VideojuegoEvent.VIDEOJUEGO_ACTUALIZADO -&gt; "actualizado";
            case VideojuegoEvent.VIDEOJUEGO_ELIMINADO -&gt; "eliminado";
            default -&gt; throw new IllegalArgumentException("Tipo de evento desconocido: " + tipo);
        };
        try {
            String payload = objectMapper.writeValueAsString(new VideojuegoEvent(tipo, videojuegoId));
            rabbitTemplate.convertAndSend(RabbitMQConfig.CATALOGO_EXCHANGE, "videojuego." + accion, payload);
        } catch (JsonProcessingException e) {
            throw new RuntimeException("No se ha podido serializar el evento", e);
        }
    }
}
</code></pre> <p><code>RabbitTemplate</code> es el equivalente en mensajería de <code>JdbcTemplate</code>, que ya conoces de Acceso a Datos: Spring Boot lo configura solo en cuanto detecta <code>spring-boot-starter-amqp</code> en el classpath, sin que lo registres tú.</p> <p>Inyecta <code>VideojuegoEventPublisher</code> en <code>VideojuegoService</code> (constructor, como todo lo demás) y llama a <code>publicar(...)</code> al final de <code>create</code>, <code>update</code> y <code>delete</code>, con el tipo correspondiente y el <code>id</code> del videojuego.</p> <p>Pregunta: <code>VideojuegoService</code> ahora depende de <code>VideojuegoEventPublisher</code>, pero no de nada de RabbitMQ directamente (ni <code>RabbitTemplate</code> aparece en <code>VideojuegoService</code>). ¿Por qué esa capa intermedia, en vez de inyectar <code>RabbitTemplate</code> directamente en <code>VideojuegoService</code>?</p>

